#include<bits/stdc++.h>
using namespace std;
char a[1005][1005];
int n,m,ans;
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
        }
    }
    for(int i=0;i<=n+1;i++){
        for(int j=0;j<=m+1;j++){
           if(a[i][j]==0){
               a[i][j]='0';
           }
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(a[i][j]>'0'){
                ans+=2;
            }
            if(a[i][j]>a[i-1][j]){
                ans+=a[i][j]-a[i-1][j];
            }
            if(a[i][j]>a[i+1][j]){
                ans+=a[i][j]-a[i+1][j];
            }
            if(a[i][j]>a[i][j-1]){
                ans+=a[i][j]-a[i][j-1];
            }
            if(a[i][j]>a[i][j+1]){
                ans+=a[i][j]-a[i][j+1];
            }
        }
    }
    cout<<ans;
    return 0;
}
